class Solution:
    def splitString(self, s):
        n = len(s)
        def rec(start, prev):
            if start == n:
                return True
            for end in range(start + 1, n + 1):
                val = int(s[start:end])
                if val == prev - 1 and rec(end, val):
                    return True
                if val >= prev:
                    break
            return False
        for end in range(1, n):
            first = int(s[:end])
            if rec(end, first):
                return True
        return False

