class Solution:
    def splitString(self, s):
        n = len(s)
        def dfs(start, prev):
            if start == n:
                return True
            val = 0
            for i in range(start, n):
                val = val * 10 + int(s[i])
                if val == prev - 1 and dfs(i + 1, val):
                    return True
                if val >= prev:
                    break
            return False
        val = 0
        for i in range(n - 1):
            val = val * 10 + int(s[i])
            if dfs(i + 1, val):
                return True
        return False

